#include <stdio.h>
#include <limits.h>
#define INF INT_MAX
#define N 250
int min(int a, int b) { return a < b ? a : b; }
int dijkstra(int graph[N][N], int src, int dest) {
    int dist[N];
    for (int i = 0; i < N; i++) dist[i] = INF;
    dist[src] = 0;
    for (int i = 0; i < N - 1; i++) {
        for (int u = 0; u < N; u++) {
            for (int v = 0; v < N; v++) {
                if (graph[u][v] != INF && dist[u] != INF && dist[u] + graph[u][v] < dist[v]) {
                    dist[v] = dist[u] + graph[u][v];
                }
            }
        }
    }
    return dist[dest];
}
int main() {
    int N, M;
    scanf("%d", &N);
    int graph[N][N];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            scanf("%d", &graph[i][j]);
        }
    }
    scanf("%d", &M);
    for (int i = 0; i < M; i++) {
        int S, G, D;
        scanf("%d %d %d", &S, &G, &D);
        int time_with_gas_station = dijkstra(graph, S, G) + dijkstra(graph, G, D);
        int time_without_gas_station = dijkstra(graph, S, D);
        printf("%d %d\n", time_with_gas_station, time_with_gas_station - time_without_gas_station);
    }
    return 0;
}

