    std::vector<int> dist(N, INF);
    dist[src] = 0;
    for (int i = 0; i < N - 1; i++) {
        for (int u = 0; u < N; u++) {
            for (int v = 0; v < N; v++) {
                if (graph[u][v] != INF && dist[u] != INF && dist[u] + graph[u][v] < dist[v]) {
                    dist[v] = dist[u] + graph[u][v];
                }
            }
        }
    }
    return dist[dest];
}
int main() {
    int N, M;
    std::cin >> N;
    std::vector<std::vector<int>> graph(N, std::vector<int>(N));
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            std::cin >> graph[i][j];
        }
    }
    std::cin >> M;
    for (int i = 0; i < M; i++) {
        int S, G, D;
        std::cin >> S >> G >> D;
        int time_with_gas_station = dijkstra(graph, S, G) + dijkstra(graph, G, D);
