import java.util.Scanner;
public class Main {
    static final int INF = Integer.MAX_VALUE;
    static final int N = 250;
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[][] graph = new int[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                graph[i][j] = scanner.nextInt();
            }
        }
        int M = scanner.nextInt();
        for (int i = 0; i < M; i++) {
            int S = scanner.nextInt();
            int G = scanner.nextInt();
            int D = scanner.nextInt();
            int time_with_gas_station = dijkstra(graph, S, G) + dijkstra(graph, G, D);
            int time_without_gas_station = dijkstra(graph, S, D);
            System.out.println(time_with_gas_station + " " + (time_with_gas_station - time_without_gas_station));
        }
    }
    public static int dijkstra(int[][] graph, int src, int dest) {
        int[] dist = new int[N];
        for (int i = 0; i < N; i++) dist[i] = INF;
        dist[src] = 0;
        for (int i = 0; i < N - 1; i++) {
            for (int u = 0; u < N; u++) {
                for (int v = 0; v < N; v++) {
                    if (graph[u][v] != INF && dist[u] != INF && dist[u] + graph[u][v] < dist[v]) {
                        dist[v] = dist[u] + graph[u][v];
                    }
                }
            }
        }
        return dist[dest];
    }
}

