function dijkstra(graph, src, dest) {
    const dist = new Array(N).fill(INF);
    dist[src] = 0;
    for (let i = 0; i < N - 1; i++) {
        for (let u = 0; u < N; u++) {
            for (let v = 0; v < N; v++) {
                if (graph[u][v] !== INF && dist[u] !== INF && dist[u] + graph[u][v] < dist[v]) {
